#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int start;
    int size;
    int free;
    int process_id;
} MemoryBlock;

int best_fit(MemoryBlock *blocks, int n, int request_size, int pid) {
    int best_idx = -1;
    int min_size = __INT_MAX__;

    // Find smallest hole large enough
    for (int i = 0; i < n; i++) {
        if (blocks[i].free && blocks[i].size >= request_size) {
            if (blocks[i].size < min_size) {
                min_size = blocks[i].size;
                best_idx = i;
            }
        }
    }

    if (best_idx == -1) return -1;  // No fit found

    // Allocate and split if needed
    if (blocks[best_idx].size > request_size) {
        // Create new free block
        MemoryBlock new_block = {
            blocks[best_idx].start + request_size,
            blocks[best_idx].size - request_size,
            1, -1
        };
        blocks[best_idx].size = request_size;
        // In real implementation, insert new_block into array
    }

    blocks[best_idx].free = 0;
    blocks[best_idx].process_id = pid;

    return blocks[best_idx].start;
}

int main() {
    MemoryBlock memory[] = {
        {0, 100, 1, -1},
        {100, 200, 1, -1},
        {300, 150, 1, -1},
        {450, 250, 1, -1}
    };

    int addr = best_fit(memory, 4, 80, 1);
    printf("Best fit allocation at address: %d\n", addr);

    return 0;
}

class MemoryManagementUnit {
    private int baseRegister;
    private int limitRegister;

    public MemoryManagementUnit(int base, int limit) {
        this.baseRegister = base;
        this.limitRegister = limit;
    }

    // Translate logical address to physical address
    public int translate(int logicalAddress) {
        // Check for valid address (bounds checking)
        if (logicalAddress < 0 || logicalAddress >= limitRegister) {
            throw new SecurityException(
                "Memory Protection Violation: Address " + 
                logicalAddress + " exceeds limit " + limitRegister
            );
        }

        // Physical address = Base + Logical address
        int physicalAddress = baseRegister + logicalAddress;
        return physicalAddress;
    }

    // Load a process into memory
    public void loadProcess(int processSize, int baseAddress) {
        this.baseRegister = baseAddress;
        this.limitRegister = processSize;
    }

    public int getBase() { return baseRegister; }
    public int getLimit() { return limitRegister; }
}

public class AddressTranslationDemo {
    public static void main(String[] args) {
        // Create MMU for a process loaded at physical address 1000
        MemoryManagementUnit mmu = new MemoryManagementUnit(1000, 500);

        // Simulate address translations
        int[] logicalAddresses = {0, 50, 100, 250, 499};

        System.out.println("Base Register: " + mmu.getBase());
        System.out.println("Limit Register: " + mmu.getLimit());
        System.out.println("-------------------------");

        for (int logical : logicalAddresses) {
            int physical = mmu.translate(logical);
            System.out.println("Logical: " + logical + 
                " -> Physical: " + physical);
        }

        // Test protection - this will throw exception
        try {
            mmu.translate(600);  // Beyond limit
        } catch (SecurityException e) {
            System.out.println("\nProtection Trap: " + e.getMessage());
        }
    }
}
